DROP TABLE IF EXISTS `Tests_interview`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `Tests_interview` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(200) NOT NULL,
  `challengescount` int(11) DEFAULT '5',
  `maxresponsestarttime` int(11) DEFAULT '300',
  `topic_id` int(11) DEFAULT NULL,
  `topicname` varchar(200) DEFAULT NULL,
  `interviewer_id` int(11) NOT NULL,
  `medium` varchar(15) NOT NULL DEFAULT 'audio',
  `language` varchar(20) NOT NULL DEFAULT 'english',
  `createdate` datetime NOT NULL,
  `publishdate` datetime DEFAULT NULL,
  `status` tinyint(1) DEFAULT '1',
  `maxscore` int(11) DEFAULT '0',
  `maxduration` int(11) DEFAULT '3600',
  `randomsequencing` tinyint(1) DEFAULT '1',
  `interviewlinkid` varchar(200) NOT NULL,
  `scope` varchar(50) NOT NULL DEFAULT 'public',
  `quality` varchar(4) NOT NULL DEFAULT 'INT',
  `challengesfilepath` text NOT NULL,
  `introfilepath` text,
  `filetype` varchar(4) DEFAULT 'wav',
  `realtime` tinyint(1) DEFAULT '1',
  PRIMARY KEY (`id`),
  KEY `topic_id` (`topic_id`),
  KEY `interviewer_id` (`interviewer_id`),
  CONSTRAINT `Tests_interview_ibfk_1` FOREIGN KEY (`topic_id`) REFERENCES `Tests_topic` (`id`),
  CONSTRAINT `Tests_interview_ibfk_2` FOREIGN KEY (`interviewer_id`) REFERENCES `Auth_user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=500 DEFAULT CHARSET=latin1;
/*!40101 SET character_set_client = @saved_cs_client */;

