INSERT INTO `careers` VALUES (1,'Country Head - Internet/online','Country Head - Internet/online','TST-CH/IO','Reporting directly to the GM of Asia-Pacific and a China Board (comprised of the CEO, COO and Asia President), Managing Director of India is expected to drive business forward and make an immediate positive impact on the company\'s overall strategy and in particular the right partnership/alliance with top domestic internet players.<br />He/she must be someone who brings credibility and leadership skills to quickly establish rapport with key stakeholders externally and internally. The ideal candidate will have the overriding mandate to also deliver revenue/profit expectations through strengthening the India team, operationalize a winning go-to-market plan, and drive the critical partnership discussions with clients group.','0000-00-00 00:00:00','0000-00-00 00:00:00',1,2500000,'p.a.',20,'permanent',20,'IT Software - eCommerce , Internet Technologies','New Delhi','Development',0,'Supriyo Mitra','0000-00-00 00:00:00','','supmit@gmail.com');
/*!40000 ALTER TABLE `careers` ENABLE KEYS */;
